FROM custom_attributes
WHERE value = 'Hidden';

SELECT schema_id, MAX(change_date) AS latest_change_date
FROM metadata_logs
GROUP BY schema_id;

SELECT schema_name
FROM schemas
WHERE schema_id = 0;

SELECT ca.attribute_name
FROM custom_attributes ca
WHERE ca.attribute_name = 'UI Display' AND ca.value = 'Visible';

SELECT schema_name
FROM schemas
WHERE version = (SELECT MAX(version) FROM schemas);
